SELECT COUNT(*) FROM SERVIDOR S WHERE LOWER(S.AREA_INGRESSO) = LOWER('sociologia') AND LOWER(S.SIGLA_CAMPUS) = LOWER('sen') AND LOWER(S.CONTRATO) = LOWER('efetivos') AND SAIU_DO_IFG = FALSE AND EXISTS (SELECT 1 FROM CALC_HORA_AULA_MEDIA C WHERE C.SIAPE = S.PK_SIAPE AND C.ANO = 2021 AND C.SEMESTRE = 2)